const hashIpForUser = (ip: string, userId: string): string => {
  if (!ip || !userId) return '';
  return createHmac('sha256', env.PII_HASH_SECRET).update(`session:ip:${userId}:${ip}`).digest('hex').slice(0, 32);
};

